// IVD (Ideographic Variation Database) — Unicode IVS registry
// Source: https://www.unicode.org/ivd/data/2022-09-13/IVD_Sequences.txt
// 15290 base characters, 39303 total IVS sequences
// Packed binary: 3 bytes base CP + 1 byte count + N bytes VS offsets

// prettier-ignore
const IVD_DATA = "";

let ivdBytes: Uint8Array | null = null;
let ivdIndex: Map<number, number> | null = null; // base CP -> byte offset

function ensureIvd() {
  if (ivdBytes) return;
  const bin = atob(IVD_DATA);
  ivdBytes = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) ivdBytes[i] = bin.charCodeAt(i);
  
  // Build index for fast lookup
  ivdIndex = new Map();
  let offset = 0;
  while (offset < ivdBytes.length) {
    const cp = (ivdBytes[offset] << 16) | (ivdBytes[offset + 1] << 8) | ivdBytes[offset + 2];
    ivdIndex.set(cp, offset);
    const count = ivdBytes[offset + 3];
    offset += 4 + count;
  }
}

/** Get the number of IVS variants for a base code point. Returns 0 if none. */
export function getIvsCount(cp: number): number {
  ensureIvd();
  const offset = ivdIndex!.get(cp);
  if (offset === undefined) return 0;
  return ivdBytes![offset + 3];
}

/** Get all IVS variant selectors for a base code point. Returns empty array if none. */
export function getIvsVariants(cp: number): number[] {
  ensureIvd();
  const offset = ivdIndex!.get(cp);
  if (offset === undefined) return [];
  const count = ivdBytes![offset + 3];
  const variants: number[] = [];
  for (let i = 0; i < count; i++) {
    const b = ivdBytes![offset + 4 + i];
    if (b <= 0xEF) variants.push(0xE0100 + b);
    else variants.push(0xFE00 + (b - 0xF0));
  }
  return variants;
}
